const data = $input.first().json;
const errors = [];
if (!data.video_url) errors.push('video_url is required');
if (!data.title) errors.push('title is required');
if (!data.source_id) errors.push('source_id is required');
if (data.video_url && !String(data.video_url).startsWith('http')) errors.push('video_url must be absolute');
if (errors.length) throw new Error(`Invalid video data: ${errors.join(', ')}`);
return [{ json: data }];

const data = $input.first().json;
const tags = Array.isArray(data.hashtags) ? data.hashtags.map(t => String(t).startsWith('#') ? t : `#${t}`).join(' ') : '#BongBanViet #TableTennis #BongBan';
const caption = [
  data.product_name ? `${data.product_name}: co gi dang chu y?` : data.title,
  data.description || 'Goi y nhanh cho nguoi choi bong ban phong trao.',
  'Xem het video va nhan tin neu ban can tu van setup.',
  tags
].join('\n');
return [{ json: { ...data, caption } }];

const result = $input.first().json;
// TODO: Persist publish_id/status to internal source system.
return [{ json: { channel: 'tiktok', ok: true, result, saved_at: new Date().toISOString() } }];
